#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>

#define MAX_T 100
#define MAX_A 1000000000
#define MAX_M 1000000000

int main() {
    int T, A, M, i, j, count, *divisors, *result;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &A, &M);
        divisors = (int*)malloc((M - A) * sizeof(int));
        count = 0;
        for (i = 1; i <= sqrt(M - A); i++) {
            if ((M - A) % i == 0) {
                divisors[count++] = i;
                if (i != (M - A) / i) {
                    divisors[count++] = (M - A) / i;
                }
            }
        }
        qsort(divisors, count, sizeof(int), compare);
        result = (int*)malloc(count * sizeof(int));
        for (i = 0; i < count; i++) {
            result[i] = (M - A) / divisors[i];
        }
        printf("%d\n", count);
        for (i = 0; i < count; i++) {
            printf("%d%c", result[i], i + 1 < count ? ' ' : '\n');
        }
        free(divisors);
        free(result);
    }
    return 0;
}

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

