public class Main {
    public static void main(String[] args) {
        java.util.Scanner sc = new java.util.Scanner(System.in);
        int T, A, M, i, j, count;
        sc.nextInt();
        while (sc.hasNextInt()) {
            T = sc.nextInt();
            while (T-- > 0) {
                A = sc.nextInt();
                M = sc.nextInt();
                java.util.Arrays.sort(getDivisors(M - A));
                System.out.println(getDivisors(M - A).length);
                for (i = 0; i < getDivisors(M - A).length; i++) {
                    System.out.print((M - A) / getDivisors(M - A)[i]);
                    if (i + 1 < getDivisors(M - A).length) {
                        System.out.print(' ');
                    } else {
                        System.out.println();
                    }
                }
            }
        }
    }

    public static int[] getDivisors(int n) {
        int count = 0;
        int[] divisors = new int[n + 1];
        for (int i = 1; i <= Math.sqrt(n); i++) {
            if (n % i == 0) {
                divisors[count++] = i;
                if (i != n / i) {
                    divisors[count++] = n / i;
                }
            }
        }
        return divisors;
    }
}

